class WorkComponent {
    constructor(cdr) {
        this.cdr = cdr;
        this.OFFSET = 0;
        this.closedHeight = 0;
        this.openHeight = 1500;
        this.hidden = true;
    }
    ngAfterViewInit() {
        this.closedHeight = this.firstElement.nativeElement.offsetHeight + this.OFFSET;
        console.log(this.closedHeight);
        // this.openHeight = this.wrapperElement.nativeElement.offsetHeight + this.OFFSET;
        this.cdr.detectChanges();
    }
    toggleWork() {
        this.hidden = !this.hidden;
    }
}


